import{_ as e,c as t,o as a,U as n}from"./chunks/framework.V7QYn7G9.js";const m=JSON.parse('{"title":"Development environment","description":"","frontmatter":{},"headers":[],"relativePath":"contrib/environment.md","filePath":"contrib/environment.md","lastUpdated":1707607520000}'),o={name:"contrib/environment.md"},r=n('<h1 id="development-environment" tabindex="-1">Development environment <a class="header-anchor" href="#development-environment" aria-label="Permalink to &quot;Development environment&quot;">​</a></h1><h3 id="editor" tabindex="-1">Editor <a class="header-anchor" href="#editor" aria-label="Permalink to &quot;Editor&quot;">​</a></h3><p>We recommend using <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">Visual Studio Code</a>. It is a free and open source editor that is available for all platforms. You can add some extensions to it to make it more useful for you.</p><h3 id="ruby" tabindex="-1">Ruby <a class="header-anchor" href="#ruby" aria-label="Permalink to &quot;Ruby&quot;">​</a></h3><p>Lesli uses <a href="https://www.ruby-lang.org/" target="_blank" rel="noreferrer">Ruby</a> as its primary programming language. The backend is written in Ruby with <a href="https://rubyonrails.org/" target="_blank" rel="noreferrer">Ruby on Rails</a> as its framework. <strong>Lesli use the ruby version 3.1.2.</strong></p><h4 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h4><p>Ruby is available for all platforms. If you need more details for the installation you can following the instructions <a href="https://www.ruby-lang.org/en/documentation/quickstart/" target="_blank" rel="noreferrer">here</a>.</p><p>To install Ruby, you have a couple of options. You can install <a href="https://www.ruby-lang.org/en/" target="_blank" rel="noreferrer">Ruby from the official website</a>. If you choose to install it from there, you will have only one version of ruby and this can be a problem if you want to use multiple versions of ruby in different projects.</p><h4 id="version-managers-recommended" tabindex="-1">Version Managers (recommended) <a class="header-anchor" href="#version-managers-recommended" aria-label="Permalink to &quot;Version Managers (recommended)&quot;">​</a></h4><p>If you choose to install it with a version manager, you will have multiple versions of ruby, this is a good option if you use multiple versions of ruby in different projects.</p><p>In the Ruby community, there are two popular managers responsible for installing and maintaining multiple Ruby versions <a href="https://rvm.io/" target="_blank" rel="noreferrer">rvm</a> (recommended) and <a href="https://rbenv.io/" target="_blank" rel="noreferrer">rbenv</a>.</p><p><strong>RVM pros over Rbenv:</strong></p><ul><li>RVM is easier to install than Rbenv.</li><li>RVM has more features than Rbenv.</li><li>RVM includes a built-in Ruby installation mechanism while Rbenv does not.</li></ul><p><strong>Rbenv pros over RVM</strong>:</p><ul><li>Rbenv is lightweight, RVM is heavier.</li><li>Rbenv is more developer-friendly than RVM.</li><li>Rbenv has a dedicated plugin for Ruby installation mechanism, RVM has it built-in.</li></ul><p>After you install ruby you need to install rails and bundler. You can use the following commands in your terminal:</p><p>Install rails and bundler</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gem</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rails</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundler</span></span></code></pre></div><h3 id="node-js" tabindex="-1">Node.js <a class="header-anchor" href="#node-js" aria-label="Permalink to &quot;Node.js&quot;">​</a></h3><p>Node.js is a JavaScript runtime built on Chrome&#39;s V8 JavaScript engine. It is used for running JavaScript in the server side. Lesli uses node to run webpack, vue and other javascript libraries for the frontend. <strong>To work with Lesli you can use the LTS version of Node.</strong></p><p><strong>Installation:</strong> Node.js is available for all platforms. If you need more details for the installation of specific version you can following the instructions <a href="https://nodejs.org/en/" target="_blank" rel="noreferrer">here</a>.</p><p><strong>Version Manager (recommended):</strong> Node Version Manager (nvm) is a tool that allows the user to switch between different versions of Nodejs, helping to reduce overhead when reproducing production bugs in development environments. <a href="https://github.com/nvm-sh/nvm" target="_blank" rel="noreferrer">The default installation</a> is only supported on macOS and Linux environments. Windows users can follow the instructions <a href="https://content.breatheco.de/es/how-to/nvm-install-windows" target="_blank" rel="noreferrer">here</a>. For more information about nvm, you can go to this <a href="https://github.com/nvm-sh/nvm" target="_blank" rel="noreferrer">link</a>.</p><p>Then you need to install yarn. You can use the following command in your</p><p>terminal:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yarn</span></span></code></pre></div><h3 id="postgresql" tabindex="-1">Postgresql <a class="header-anchor" href="#postgresql" aria-label="Permalink to &quot;Postgresql&quot;">​</a></h3><p>Lesli uses <a href="https://www.postgresql.org/" target="_blank" rel="noreferrer">Postgresql</a> as its database engine. It is a free and open source database that is available for all platforms. You can install postgresql on your computer and then you can use it to create a database for Lesli. The following links provide more information about the installation of postgresql. - <a href="https://www.postgresqltutorial.com/postgresql-getting-started/install-postgresql/" target="_blank" rel="noreferrer">Install PostgreSQL on Windows</a> - <a href="https://www.postgresqltutorial.com/postgresql-getting-started/install-postgresql-macos/" target="_blank" rel="noreferrer">Install PostgreSQL on macOS</a> - <a href="https://www.postgresqltutorial.com/postgresql-getting-started/install-postgresql-linux/" target="_blank" rel="noreferrer">Install PostgreSQL on Linux</a></p><h3 id="git" tabindex="-1">Git <a class="header-anchor" href="#git" aria-label="Permalink to &quot;Git&quot;">​</a></h3><p>Git is a version control system that is used to track changes in files. It is used to manage the codebase of Lesli.</p><h3 id="github" tabindex="-1">Github <a class="header-anchor" href="#github" aria-label="Permalink to &quot;Github&quot;">​</a></h3><p>Github is a web-based Git repository hosting service that is used to store the codebase of Lesli. For download the codebase you need to clone the repository with ssh or with https. If you want to use ssh you need to create a ssh keys.</p><h3 id="install-engines" tabindex="-1">Install engines <a class="header-anchor" href="#install-engines" aria-label="Permalink to &quot;Install engines&quot;">​</a></h3><p>To install engines you need to clone the repository inside the engines folder.</p>',33),s=[r];function i(l,h,d,u,p,c){return a(),t("div",null,s)}const b=e(o,[["render",i]]);export{m as __pageData,b as default};
